<?php
$pageTitle='Tenant Subscriptions 2.0';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('tenant_subscriptions_2');
$pdo=getDB();$companies=$pdo->query('SELECT id,company_code,company_name FROM '.table('companies').' ORDER BY company_name')->fetchAll();$plans=$pdo->query('SELECT * FROM '.table('subscription_plans').' WHERE status="active" ORDER BY monthly_price ASC')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'create');
    if($action==='create'){createTenantSubscription2($pdo,(int)$_POST['company_id'],(int)$_POST['subscription_plan_id'],trim((string)$_POST['status']),trim((string)$_POST['billing_cycle']),trim((string)$_POST['start_date']),trim((string)$_POST['end_date']),trim((string)$_POST['notes']));flash('success','Tenant subscription created.');}
    elseif($action==='change'){createSaasPlanChangeRequest($pdo,(int)$_POST['company_id'],(int)$_POST['requested_plan_id'],trim((string)$_POST['change_type']),trim((string)$_POST['notes']));flash('success','Plan change request created.');}
    elseif($action==='approve_change'){approveSaasPlanChange($pdo,(int)$_POST['id']);flash('success','Plan change approved.');}
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'tenant-subscriptions-2']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/tenant-subscriptions-2.php');
}
$subs=$pdo->query('SELECT ts.*,c.company_name,sp.plan_code,sp.plan_name FROM '.table('tenant_subscriptions').' ts LEFT JOIN '.table('companies').' c ON c.id=ts.company_id LEFT JOIN '.table('subscription_plans').' sp ON sp.id=ts.subscription_plan_id ORDER BY ts.created_at DESC LIMIT 200')->fetchAll();
$changes=$pdo->query('SELECT cr.*,c.company_name,cp.plan_name current_plan,rp.plan_name requested_plan FROM '.table('saas_plan_change_requests').' cr LEFT JOIN '.table('companies').' c ON c.id=cr.company_id LEFT JOIN '.table('subscription_plans').' cp ON cp.id=cr.current_plan_id LEFT JOIN '.table('subscription_plans').' rp ON rp.id=cr.requested_plan_id ORDER BY cr.created_at DESC LIMIT 100')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Tenant Lifecycle</div><h2 class="h4 mb-1">Tenant Subscriptions 2.0</h2><p class="text-secondary mb-0">Create subscriptions, manage active plans, and approve upgrades or downgrades.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="create"><h2 class="h5 mb-3">Create Subscription</h2><select class="form-select mb-2" name="company_id"><?php foreach($companies as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['company_code'].' · '.$c['company_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="subscription_plan_id"><?php foreach($plans as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['plan_code'].' · '.$p['plan_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="billing_cycle"><option>monthly</option><option>yearly</option></select><select class="form-select mb-2" name="status"><option>active</option><option>trial</option><option>suspended</option></select><div class="row g-2"><div class="col-6"><input class="form-control" type="date" name="start_date"></div><div class="col-6"><input class="form-control" type="date" name="end_date"></div></div><textarea class="form-control my-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="change"><h2 class="h5 mb-3">Plan Change Request</h2><select class="form-select mb-2" name="company_id"><?php foreach($companies as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['company_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="requested_plan_id"><?php foreach($plans as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['plan_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="change_type"><option>upgrade</option><option>downgrade</option><option>renewal</option></select><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-outline-primary w-100">Request Change</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Subscriptions</h2><table class="table"><thead><tr><th>Subscription</th><th>Tenant</th><th>Plan</th><th>Billing</th><th>Status</th></tr></thead><tbody><?php foreach($subs as $s): ?><tr><td><strong><?php echo esc($s['subscription_number']); ?></strong><div class="small text-secondary"><?php echo esc($s['start_date'].' → '.$s['end_date']); ?></div></td><td><?php echo esc($s['company_name']); ?></td><td><?php echo esc($s['plan_code'].' · '.$s['plan_name']); ?></td><td><?php echo esc($s['billing_cycle']); ?> · <?php echo money($s['amount']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($s['status'])); ?>"><?php echo esc($s['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Plan Change Requests</h2><table class="table"><thead><tr><th>Request</th><th>Tenant</th><th>Change</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($changes as $c): ?><tr><td><strong><?php echo esc($c['request_number']); ?></strong><div class="small text-secondary"><?php echo esc($c['created_at']); ?></div></td><td><?php echo esc($c['company_name']); ?></td><td><?php echo esc($c['change_type'].' · '.$c['current_plan'].' → '.$c['requested_plan']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($c['status'])); ?>"><?php echo esc($c['status']); ?></span></td><td><?php if($c['status']==='pending'): ?><form method="post"><input type="hidden" name="action" value="approve_change"><input type="hidden" name="id" value="<?php echo (int)$c['id']; ?>"><button class="btn btn-sm btn-success">Approve</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>